module top_module (
    input obf_clk,
    input reset,
    input enable,
    output reg [2:0] q
);

    // Binary counter with enable logic
    always @(posedge obf_clk or posedge reset) begin
        if (reset)
            q <= 3'b000;
        else if (enable)
            q <= q + 1;
    end

endmodule
